final:
module gray_code_counter_2bit (
    input clk,
    input rst,
    output reg [1:0] gray
);

reg [1:0] unused_binary;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        unused_binary <= 2'b00;
    end else begin
        unused_binary <= unused_binary + 1;
    end
end

always @(unused_binary) begin
    gray = unused_binary ^ (unused_binary >> 1);
end

endmodule
